const from = $json.from || '';
const subject = $json.subject || '';
const body = $json.body || '';

const userMessage = `CATEGORY DEFINITIONS:
- setup: Technical help - connections, authentication errors, sync issues, field mapping, OAuth, API tokens
- security: Compliance/security - encryption, HIPAA, SOC2, GDPR, ISO27001, data storage, penetration tests, BAA
- pricing: Plan costs - comparing plans, discounts, API limits, overage, upgrades, trial, nonprofit rates
- hr: Job applications, internship inquiries, career questions
- escalate_sales: Enterprise pricing, partnerships, reseller deals, contract renewals
- escalate_finance: Billing disputes, invoice requests, payment failures, refunds
- escalate_legal: DPA requests, GDPR compliance docs, legal contracts
- spam: Recruiting spam, irrelevant marketing
- misdirected: Email for a different company or wrong recipient

EXAMPLES:
From: j@acme.com | Subject: Salesforce auth error | Body: Getting Authentication Failed. -> {"category":"setup"}
From: h@hospital.org | Subject: HIPAA | Body: Do you offer a BAA? -> {"category":"security"}
From: l@co.io | Subject: Pricing | Body: Difference between Professional and Enterprise? -> {"category":"pricing"}
From: j@corp.com | Subject: Enterprise deal | Body: 50+ integrations, reseller arrangement. -> {"category":"escalate_sales"}
From: f@co.com | Subject: Invoice March | Body: Need invoice for March subscription. -> {"category":"escalate_finance"}
From: l@co.com | Subject: DPA request | Body: Need Data Processing Agreement for GDPR. -> {"category":"escalate_legal"}
From: r@staff.com | Subject: Top engineers | Body: I have candidates for your engineering team. -> {"category":"spam"}
From: c@pizza.com | Subject: Order late | Body: My pizza hasn't arrived. -> {"category":"misdirected"}
From: s@co.com | Subject: Job application | Body: Applying for software engineer role. -> {"category":"hr"}

RULES: partnership/enterprise/reseller -> escalate_sales NOT pricing | legal doc/DPA -> escalate_legal NOT security | billing/invoice -> escalate_finance NOT pricing

Email to classify:
From: ${from}
Subject: ${subject}
Body:
${body}

Respond ONLY with valid JSON: {"category":"category_name"}`;

return { json: { ...$json, userMessage } };

const responseText = $json.text || $json.output || '';
const prevData = $('Build Classify Prompt').item.json;

const VALID = ['setup','security','pricing','hr','escalate_sales','escalate_support','escalate_finance','escalate_legal','spam','misdirected'];

let category = null;
try {
  const cleaned = responseText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  category = parsed.category || null;
} catch (e) {
  const match = responseText.match(/"category"\s*:\s*"([^"]+)"/);
  if (match) category = match[1];
}

if (category) category = category.toLowerCase().trim();
if (!category || !VALID.includes(category)) category = 'escalate_support';

return {
  json: {
    from: prevData.from,
    subject: prevData.subject,
    body: prevData.body,
    isEvaluation: prevData.isEvaluation,
    expected_category: prevData.expected_category || '',
    category
  }
};

const responseText = $json.text || $json.output || '';
const prevData = $('Build Reply Prompt').item.json;

let draft_reply = '';
try {
  const cleaned = responseText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  draft_reply = parsed.draft_reply || '';
} catch (e) {
  const match = responseText.match(/"draft_reply"\s*:\s*"((?:[^"\\]|\\.)*)"/s);
  if (match) {
    draft_reply = match[1].replace(/\\n/g, '\n').replace(/\\"/g, '"');
  } else {
    draft_reply = responseText.trim();
  }
}

if (!draft_reply || draft_reply.trim().length === 0) {
  draft_reply = 'Thank you for contacting Nexus Integrations. Our team will review your message and respond shortly.';
}

return {
  json: {
    from: prevData.from,
    subject: prevData.subject,
    body: prevData.body,
    isEvaluation: prevData.isEvaluation,
    expected_category: prevData.expected_category || '',
    category: prevData.category,
    draft_reply
  }
};

const category = $json.category || '';
const draft_reply = $json.draft_reply || '';
const expected_category = $json.expected_category || '';
const from = $json.from || '';
const subject = $json.subject || '';
const body = $json.body || '';
const match = category === expected_category ? 'YES' : 'NO';

const userMessage = `Expected Category: ${expected_category}
Actual Category: ${category}
Category Match: ${match}

Original Email:
From: ${from}
Subject: ${subject}
Body: ${body}

Draft Reply:
${draft_reply}

Score this response. If Category Match is NO, score must be 0.
Respond ONLY with valid JSON: {"score":1,"reason":"one sentence"} or {"score":0,"reason":"one sentence"}`;

return { json: { ...$json, userMessage } };

const responseText = $json.text || $json.output || '';
const prevData = $('Build Score Prompt').item.json;

let score = 0;
let reason = 'Could not parse score response';

try {
  const cleaned = responseText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
  const parsed = JSON.parse(cleaned);
  score = (parsed.score === 1 || parsed.score === '1' || parsed.score === true) ? 1 : 0;
  reason = parsed.reason || '';
} catch (e) {
  const scoreMatch = responseText.match(/"score"\s*:\s*(\d)/);
  const reasonMatch = responseText.match(/"reason"\s*:\s*"([^"]+)"/);
  if (scoreMatch) score = parseInt(scoreMatch[1], 10) === 1 ? 1 : 0;
  if (reasonMatch) reason = reasonMatch[1];
}

const expected = (prevData.expected_category || '').toLowerCase().trim();
const actual = (prevData.category || '').toLowerCase().trim();
if (expected && actual !== expected) {
  score = 0;
  reason = `Category mismatch: expected '${expected}', got '${actual}'. ${reason}`;
}

if (score !== 0 && score !== 1) score = 0;

return { json: { ...prevData, score, reason } };
